import akka.http.scaladsl.Http
import akka.http.scaladsl.model.{HttpRequest, HttpResponse, MediaTypes}
import akka.http.scaladsl.server.Directives._
import akka.actor.ActorSystem
import akka.stream.ActorMaterializer
import scala.xml.XML

object ConfigService extends App {
  implicit val system: ActorSystem = ActorSystem("config-service")
  implicit val materializer: ActorMaterializer = ActorMaterializer()
  implicit val executionContext = system.dispatcher

  val route =
    path("parse-config") {
      post {
        entity(as[String]) { xmlString =>
          try {
            val xml = XML.loadString(xmlString)
            val settings = (xml \\ "setting").map { node =>
              (node \ "@name").text -> (node \ "@value").text
            }.toMap
            complete(HttpResponse(entity = settings.toString()))
          } catch {
            case e: Exception =>
              complete(HttpResponse(400, entity = s"Invalid XML: ${e.getMessage}"))
          }
        }
      }
    }

  val bindingFuture = Http().bindAndHandle(route, "localhost", 8080)
  println("Server online at http://localhost:8080/")
}